import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

const formatPrice = (p) => (p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—');

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  // Use snake_case internally to match exactly what your API query builder needs
  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    property_type: searchParams.get('property_type') || '', 
    min_rent: searchParams.get('min_rent') || '',
    max_rent: searchParams.get('max_rent') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parking_spaces: searchParams.get('parking_spaces') || '',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);

  const debounceRef = useRef(null);

  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);
    try {
      // We pass the filters directly because api.js now handles the query building
      const response = await searchRentals({ 
        ...currentFilters, 
        page: currentPage 
      });
      setResults(response);
    } catch (err) {
      setError(err.message || 'Search failed.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);
      const urlParams = {};
      Object.entries(filters).forEach(([k, v]) => { if (v) urlParams[k] = v; });
      if (page > 1) urlParams.page = page;
      setSearchParams(urlParams, { replace: true });
    }, 400);
    return () => clearTimeout(debounceRef.current);
  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters(prev => ({ ...prev, [key]: value }));
    setPage(1);
  };

  const rentals = results?.data || [];
  const totalPages = results?.pagination?.lastPage || 1;
  const totalResults = results?.pagination?.total || 0;

  return (
    <div className="search-page">
      <aside className="search-page__sidebar">
        <div className="filter-panel">
          <div className="filter-panel__header">
            <h2>Filters</h2>
            <button className="btn-link" onClick={() => setFilters({
              state: '', suburb: '', postcode: '', property_type: '',
              min_rent: '', max_rent: '', bedrooms: '', bathrooms: '', parking_spaces: ''
            })}>Reset</button>
          </div>

          <div className="filter-group">
            <label className="filter-label">State</label>
            <select className="filter-select" value={filters.state} onChange={e => handleFilterChange('state', e.target.value)}>
              <option value="">All States</option>
              {states.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label">Property Type</label>
            <select className="filter-select" value={filters.property_type} onChange={e => handleFilterChange('property_type', e.target.value)}>
              <option value="">All Types</option>
              {propertyTypes.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label">Rent Range</label>
            <div className="filter-row">
              <input className="filter-input" type="number" placeholder="Min" value={filters.min_rent} onChange={e => handleFilterChange('min_rent', e.target.value)} />
              <input className="filter-input" type="number" placeholder="Max" value={filters.max_rent} onChange={e => handleFilterChange('max_rent', e.target.value)} />
            </div>
          </div>

          <div className="filter-group">
            <label className="filter-label">Bedrooms</label>
            <input className="filter-input" type="number" value={filters.bedrooms} onChange={e => handleFilterChange('bedrooms', e.target.value)} />
          </div>

          <div className="filter-group">
            <label className="filter-label">Bathrooms</label>
            <input className="filter-input" type="number" value={filters.bathrooms} onChange={e => handleFilterChange('bathrooms', e.target.value)} />
          </div>

          <div className="filter-group">
            <label className="filter-label">Parking</label>
            <input className="filter-input" type="number" value={filters.parking_spaces} onChange={e => handleFilterChange('parking_spaces', e.target.value)} />
          </div>
        </div>
      </aside>

      <main className="search-page__results">
        <header className="results-header">
          <h1>{loading ? 'Searching...' : `${totalResults.toLocaleString()} Rentals Found`}</h1>
        </header>

        <div className="results-content">
          <div className="table-scroll-container">
            <table className="results-table">
              <thead>
                <tr>
                  <th>Property</th>
                  <th>State</th>
                  <th>Type</th>
                  <th>Bed</th>
                  <th>Bath</th>
                  <th>Park</th>
                  <th>Price</th>
                </tr>
              </thead>
              <tbody>
                {!loading && rentals.map(r => (
                  <tr key={r.id} onClick={() => navigate(`/rental/${r.id}`)}>
                    <td>
                      <div className="cell-title">{r.title}</div>
                      <div className="cell-sub">{r.suburb} {r.postcode}</div>
                    </td>
                    <td>{r.state}</td>
                    <td className="text-cap">{r.propertyType}</td>
                    <td>{r.bedrooms}</td>
                    <td>{r.bathrooms}</td>
                    <td>{r.parkingSpaces}</td>
                    <td className="price-cell">{formatPrice(r.rent)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          
          {!loading && rentals.length === 0 && <EmptyState />}
          
          {/* Pagination is outside the scroll container to stay visible */}
          <div className="pagination-footer">
            <Pagination page={page} totalPages={totalPages} onPageChange={setPage} />
          </div>
        </div>
      </main>
    </div>
  );
};

export default SearchPage;
